import React, { useEffect, useRef } from "react";
import { init } from "ityped";

export default function Intro() {
  const textRef = useRef();

  useEffect(() => {
    init(textRef.current, {
      backDelay: 1500,
      backSpeed: 60,
      showCursor: true,
      strings: ["Developer"]
    });
  }, []);

  return (
    <div
      style={{
        backgroundColor: "white",
        display: "flex",
        flexDirection: "row",
        "@media screen and (max-width: 768px)": {
          flexDirection: "column",
          alignItems: "center"
        }
      }}
      className="intro"
      id="intro"
    >
      <div
        style={{
          flex: "0.5",
          overflow: "hidden"
        }}
        className="left"
      >
        <div
          style={{
            width: "700px",
            height: "700px",
            display: "flex",
            alignItems: "flex-end",
            justifyContent: "center",
            float: "right",
            "@media screen and (max-width: 768px)": {
              alignItems: "flex-start"
            }
          }}
          className="imgContainer"
        >
          <img
            src="assets/woman.png"
            alt=""
            style={{
              height: "90%",
              "@media screen and (max-width: 768px)": {
                height: "50%"
              }
            }}
          />
        </div>
      </div>

      <div
        style={{
          flex: "0.5",
          position: "relative"
        }}
        className="right"
      >
        <div
          style={{
            width: "100%",
            height: "100%",
            paddingLeft: "50px",
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            "@media screen and (max-width: 768px)": {
              paddingLeft: "0",
              alignItems: "center"
            }
          }}
          className="wrapper"
        >
          <h2 style={{ fontSize: "35px" }}>Hi There, I'm</h2>
          <h1 style={{ fontSize: "60px", margin: "10px 0" }}>Arreya Ahrom</h1>
          <h3
            style={{
              fontSize: "30px",
              "@media screen and (max-width: 768px)": {
                fontSize: "20px"
              }
            }}
          >
            I'm a <span ref={textRef} style={{ fontSize: "inherit", color: "crimson" }}></span>
          </h3>
        </div>
        <a
          href="#portfolio"
          style={{
            position: "absolute",
            bottom: "10px",
            left: "40%"
          }}
        >
          <img src="assets/down.png" alt="" style={{ width: "30px", animation: "arrowBlink 2s infinite" }} />
        </a>
      </div>
    </div>
  );
}
